/* ─────────────── NavGroup — colapsable ─────────────── */
type NavItem = { to: string; label: string; icon: string };

function NavGroup({
  label,
  groupKey,
  items,
  currentPath,
  badges = {},
  collapsed,
  onToggle,
}: {
  label: string;
  groupKey: string;
  items: readonly NavItem[];
  currentPath: string;
  badges?: BadgeMap;
  collapsed: boolean;
  onToggle: () => void;
}) {
  const hasActive = items.some(it =>
    it.to === "/app" ? currentPath === "/app" : currentPath.startsWith(it.to)
  );

  return (
    <div className="px-3 mb-2">
      {/* Header del grupo — clickeable para colapsar */}
      <button
        onClick={onToggle}
        className="w-full flex items-center justify-between px-3 py-1 rounded-md mb-1 transition-all group"
        style={{ color: hasActive ? "rgba(255,255,255,0.7)" : "rgba(255,255,255,0.28)" }}
        onMouseOver={e => (e.currentTarget.style.background = "rgba(255,255,255,0.05)")}
        onMouseOut={e => (e.currentTarget.style.background = "transparent")}
        title={collapsed ? `Expandir ${label}` : `Colapsar ${label}`}
      >
        <span className="text-[10px] font-bold uppercase tracking-wider">{label}</span>
        <i
          className={`ti ti-chevron-right text-[11px] transition-transform duration-200 ${collapsed ? "" : "rotate-90"}`}
          style={{ color: "rgba(255,255,255,0.25)" }}
        />
      </button>

      {/* Items — animación de apertura/cierre */}
      {!collapsed && (
        <nav className="space-y-0.5">
          {items.map((it) => {
            const isActive = it.to === "/app"
              ? currentPath === "/app"
              : currentPath.startsWith(it.to);
            const badge = badges[it.to];
            return (
              <Link
                key={it.to}
                href={it.to}
                className={`flex items-center gap-3 w-full px-3 py-1.5 text-sm font-semibold rounded-lg transition-all no-underline ${
                  isActive
                    ? "text-white"
                    : "text-white/60 hover:text-white hover:bg-white/8"
                }`}
                style={isActive ? {
                  background: "rgba(59,130,246,0.18)",
                  borderLeft: "3px solid #031E43",
                  paddingLeft: "9px",
                } : {}}
              >
                <i className={`ti ${it.icon} text-base flex-shrink-0`} />
                <span className="flex-1 truncate">{it.label}</span>
                {badge && (
                  <span
                    className="flex-shrink-0 min-w-[18px] h-[18px] px-1 rounded-full text-[10px] font-extrabold flex items-center justify-center leading-none"
                    style={{ backgroundColor: BADGE_COLORS[badge.variant].bg, color: BADGE_COLORS[badge.variant].text }}
                  >
                    {badge.count > 99 ? "99+" : badge.count}
                  </span>
                )}
              </Link>
            );
          })}
        </nav>
      )}

      {/* Vista colapsada: punto indicador si hay ítem activo dentro */}
      {collapsed && hasActive && (
        <div className="flex items-center gap-2 px-3 py-1">
          <span className="w-1.5 h-1.5 rounded-full bg-blue-400 flex-shrink-0" />
          <span className="text-[11px] text-white/50 truncate">
            {items.find(it => currentPath.startsWith(it.to))?.label}
          </span>
        </div>
      )}
    </div>
  );
}

